Clone_of_Requests_Po_1.query:
q = load "${App.Datasets.ERM_EmergencyRequest_YYR.FullyQualifiedName}";
q_A = filter q by date('IA_BLA.AppliedDate_Year', 'IA_BLA.AppliedDate_Month', 'IA_BLA.AppliedDate_Day') in ["current week".."current day"];
q_B = filter q by date('IA_BLA.AppliedDate_Year', 'IA_BLA.AppliedDate_Month', 'IA_BLA.AppliedDate_Day') in ["1 week ago".."current day - 1 week"];
result = group q_A by all full, q_B by all;
result = foreach result generate count(q_A) as 'Requests_CurrentPeriod', count(q_B) as 'Requests_PriorPeriod';
result = foreach result generate 'Requests_CurrentPeriod', 'Requests_PriorPeriod', case when Requests_CurrentPeriod > 0 then  (Requests_CurrentPeriod - Requests_PriorPeriod) / Requests_PriorPeriod end as 'Requests_Percent_Change_vs_Prior_Period';
result = limit result 2000;

