Requests_Table_1.query:
q = load "${App.Datasets.ERM_EmergencyRequest_YYR.FullyQualifiedName}";
q_A = filter q by {{row(IA_BLA_AppliedDate_1.selection, [0], ["min", "max"]).asDateRange("date('IA_BLA.AppliedDate_Year', 'IA_BLA.AppliedDate_Month', 'IA_BLA.AppliedDate_Day')")}};
q_B = filter q by date('IA_BLA.AppliedDate_Year', 'IA_BLA.AppliedDate_Month', 'IA_BLA.AppliedDate_Day') in ["current day".."current day"];
q_C = filter q by date('IA_BLA.AppliedDate_Year', 'IA_BLA.AppliedDate_Month', 'IA_BLA.AppliedDate_Day') in ["1 day ago".."1 day ago"];
result = group q_A by ('Address.CitywithState') full, q_B by ('Address.CitywithState') full, q_C by ('Address.CitywithState');
result = foreach result generate coalesce(q_A.'Address.CitywithState', q_B.'Address.CitywithState', q_C.'Address.CitywithState')  as 'Address.CitywithState', count(q_A) as 'Requests', count(q_B) as 'Requests_CurrentPeriod', count(q_C) as 'Requests_PriorPeriod';
result = foreach result generate 'Address.CitywithState', 'Requests', 'Requests_CurrentPeriod', 'Requests_PriorPeriod', case when Requests_CurrentPeriod > 0 then (Requests_CurrentPeriod - Requests_PriorPeriod) / Requests_PriorPeriod end as 'Requests_Percent_Change_vs_Prior_Period';
result = order result by ('Requests' desc);
result = limit result 2000;
